// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  getRides,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";
import {
  Box,
  Paper,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  IconButton,
  Link,
} from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";
import HowToRegIcon from "@mui/icons-material/HowToReg";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import LocalTaxiIcon from "@mui/icons-material/LocalTaxi";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [tab, setTab] = useState("overview");
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [approvedCaptains, setApprovedCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [
        overviewRes,
        usersRes,
        ridersRes,
        approvedRes,
        pendingRes,
        ridesRes,
      ] = await Promise.all([
        getOverview(),
        getUsers(),
        getRiders(),
        getApprovedCaptains(),
        getPendingCaptains(),
        getRides(),
      ]);

      setOverview({
        users: overviewRes.data.users,
        riders: overviewRes.data.riders,
        captains: approvedRes.data.captains.length,
        pendingCaptains: pendingRes.data.pendingCaptains.length,
        rides: overviewRes.data.rides,
      });

      setUsers(usersRes.data.users);
      setRiders(ridersRes.data.riders);
      setApprovedCaptains(approvedRes.data.captains);
      setPendingCaptains(pendingRes.data.pendingCaptains);
      setRides(ridesRes.data.rides);
    } catch (err) {
      console.error("Admin Dashboard API error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData();
    } catch (err) {
      console.error(err);
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData();
    } catch (err) {
      console.error(err);
    }
  };

  const renderCard = (title, value, icon, key) => (
    <Grid item xs={12} sm={6} md={2.4} key={key}>
      <Card
        sx={{ cursor: "pointer" }}
        onClick={() => setTab(key)}
      >
        <CardContent>
          <Box display="flex" alignItems="center">
            {icon}
            <Box ml={1}>
              <Typography variant="subtitle2">{title}</Typography>
              <Typography variant="h6">{value}</Typography>
            </Box>
          </Box>
        </CardContent>
      </Card>
    </Grid>
  );

  if (loading) return <Typography>Loading...</Typography>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Admin Dashboard
      </Typography>

      {/* Cards */}
      <Grid container spacing={2} sx={{ mb: 3 }}>
        {renderCard("Users", overview.users, <PeopleIcon />, "users")}
        {renderCard("Riders", overview.riders, <DirectionsCarIcon />, "riders")}
        {renderCard("Approved Captains", overview.captains, <HowToRegIcon />, "approved")}
        {renderCard("Pending Captains", overview.pendingCaptains, <PendingActionsIcon />, "pending")}
        {renderCard("Total Rides", overview.rides, <LocalTaxiIcon />, "rides")}
      </Grid>

      {/* Tab Content */}
      <Paper sx={{ p: 2 }}>
        {tab === "users" && (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Role</TableCell>
                <TableCell>Login Count</TableCell>
                <TableCell>Approval Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.map(u => (
                <TableRow key={u._id}>
                  <TableCell>{u.fullName}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                  <TableCell>{u.role}</TableCell>
                  <TableCell>{u.loginCount}</TableCell>
                  <TableCell>{u.approvalStatus}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}

        {tab === "riders" && (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Documents</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {riders.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.fullName}</TableCell>
                  <TableCell>{r.email}</TableCell>
                  <TableCell>{r.mobile}</TableCell>
                  <TableCell>{r.approvalStatus}</TableCell>
                  <TableCell>
                    {r.documents?.length > 0 ? (
                      r.documents.map((doc, i) => (
                        <Link key={i} href={doc.url} target="_blank" download sx={{ mr: 1 }}>
                          {doc.name}
                        </Link>
                      ))
                    ) : (
                      "-"
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}

        {tab === "approved" && (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Documents</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {approvedCaptains.map(c => (
                <TableRow key={c._id}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.email}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                  <TableCell>{c.approvalStatus}</TableCell>
                  <TableCell>
                    {c.documents?.length > 0 ? (
                      c.documents.map((doc, i) => (
                        <Link key={i} href={doc.url} target="_blank" download sx={{ mr: 1 }}>
                          {doc.name}
                        </Link>
                      ))
                    ) : (
                      "-"
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}

        {tab === "pending" && (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Documents</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptains.map(c => (
                <TableRow key={c._id}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.email}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                  <TableCell>{c.approvalStatus}</TableCell>
                  <TableCell>
                    {c.documents?.length > 0 ? (
                      c.documents.map((doc, i) => (
                        <Link key={i} href={doc.url} target="_blank" download sx={{ mr: 1 }}>
                          {doc.name}
                        </Link>
                      ))
                    ) : (
                      "-"
                    )}
                  </TableCell>
                  <TableCell>
                    <Button
                      variant="contained"
                      color="success"
                      size="small"
                      sx={{ mr: 1 }}
                      onClick={() => handleApprove(c._id)}
                    >
                      Approve
                    </Button>
                    <Button
                      variant="contained"
                      color="error"
                      size="small"
                      onClick={() => handleReject(c._id)}
                    >
                      Reject
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}

        {tab === "rides" && (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Rider</TableCell>
                <TableCell>Captain</TableCell>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Fare</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rides.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.riderId?.fullName || "-"}</TableCell>
                  <TableCell>{r.captainId?.fullName || "-"}</TableCell>
                  <TableCell>{r.pickup}</TableCell>
                  <TableCell>{r.drop}</TableCell>
                  <TableCell>{r.fare}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </Paper>
    </Box>
  );
}
